            } else {
                resolve(resultFor(result));
            }
        };

        const child = spawn(spawnCommand, spawnArgs, options);
        logWithElapsedTime(`START SPAWN child.pid: ${child.pid}`);
        child_pid = child.pid;

        let stdout = "";
        let stderr = "";

        if (child.stdin && args.stdin_text) {
            child.stdin.write(args.stdin_text);
            child.stdin.end();
        }

        if (child.stdout) {
